21	/**
22	 * Intersect schema interface.
23	 */
24	export interface IntersectSchema<
25	  TOptions extends IntersectOptions,
26	  TMessage extends ErrorMessage<IntersectIssue> | undefined,
27	> extends BaseSchema<
28	    InferIntersectInput<TOptions>,
29	    InferIntersectOutput<TOptions>,
30	    IntersectIssue | InferIssue<TOptions[number]>
31	  > {
