50	/**
51	 * Creates an intersect schema.
52	 *
53	 * @param options The intersect options.
54	 *
55	 * @returns An intersect schema.
56	 */
57	export function intersect<const TOptions extends IntersectOptions>(
58	  options: TOptions
59	): IntersectSchema<TOptions, undefined>;
60	
61	/**
62	 * Creates an intersect schema.
63	 *
64	 * @param options The intersect options.
65	 * @param message The error message.
66	 *
67	 * @returns An intersect schema.
68	 */
69	export function intersect<
70	  const TOptions extends IntersectOptions,
71	  const TMessage extends ErrorMessage<IntersectIssue> | undefined,
72	>(options: TOptions, message: TMessage): IntersectSchema<TOptions, TMessage>;
73	
74	// @__NO_SIDE_EFFECTS__
75	export function intersect(
76	  options: IntersectOptions,
77	  message?: ErrorMessage<IntersectIssue>
78	): IntersectSchema<IntersectOptions, ErrorMessage<IntersectIssue> | undefined> {
79	  return {
80	    kind: 'schema',
81	    type: 'intersect',
82	    reference: intersect,
83	    expects: _joinExpects(
84	      options.map((option) => option.expects),
85	      '&'
86	    ),
87	    async: false,
88	    options,
89	    message,
90	    get '~standard'() {
91	      return _getStandardProps(this);
92	    },
93	    '~run'(dataset, config) {
94	      // Parse input with schema of options, if not empty
95	      if (this.options.length) {
96	        // Get input value from dataset
97	        const input = dataset.value;
98	
99	        // Create variable to store outputs
100	        let outputs: unknown[] | undefined;
101	
102	        // Set typed initially to `true`
103	        // @ts-expect-error
104	        dataset.typed = true;
105	
106	        // Parse schema of each option and collect outputs
107	        for (const schema of this.options) {
108	          const optionDataset = schema['~run']({ value: input }, config);
109	
110	          // If there are issues, capture them
111	          if (optionDataset.issues) {
112	            if (dataset.issues) {
113	              // @ts-expect-error
114	              dataset.issues.push(...optionDataset.issues);
115	            } else {
116	              // @ts-expect-error
117	              dataset.issues = optionDataset.issues;
118	            }
119	
120	            // If necessary, abort early
121	            if (config.abortEarly) {
122	              dataset.typed = false;
123	              break;
124	            }
125	          }
126	
127	          // If not typed, set typed to `false`
128	          if (!optionDataset.typed) {
129	            dataset.typed = false;
130	          }
131	
132	          // Add output of option if necessary
133	          if (dataset.typed) {
134	            if (outputs) {
135	              outputs.push(optionDataset.value);
136	            } else {
137	              outputs = [optionDataset.value];
138	            }
139	          }
140	        }
141	
142	        // If outputs are typed, merge them
143	        if (dataset.typed) {
144	          // Set first output as initial output
145	          dataset.value = outputs![0];
146	
147	          // Merge outputs into one final output
148	          for (let index = 1; index < outputs!.length; index++) {
149	            const mergeDataset = _merge(dataset.value, outputs![index]);
150	
151	            // If outputs can't be merged, add issue and break loop
152	            if (mergeDataset.issue) {
153	              _addIssue(this, 'type', dataset, config, {
154	                received: 'unknown',
155	              });
156	              break;
157	            }
158	
159	            // Otherwise, set merged output
160	            dataset.value = mergeDataset.value;
161	          }
162	        }
163	
164	        // Otherwise, add intersect issue
165	      } else {
166	        _addIssue(this, 'type', dataset, config);
167	      }
168	
169	      // Return output dataset
170	      // @ts-expect-error
171	      return dataset as OutputDataset<
172	        never,
173	        IntersectIssue | BaseIssue<unknown>
174	      >;
175	    },
176	  };
177	}
