import { _getStandardProps } from '../../../utils/index.ts';
import { Recur } from '../recur.ts';

// eslint-disable-next-line @typescript-eslint/no-explicit-any
type AnyNode = Record<string, any>;

/**
 * Schema types with a single nested schema in a `value` property.
 */
const VALUE_TYPES = new Set(['record', 'map', 'set']);

/**
 * Schema types with a single nested schema in a `wrapped` property.
 */
const WRAPPED_TYPES = new Set([
  'optional',
  'nullable',
  'nullish',
  'exact_optional',
  'non_optional',
  'non_nullable',
  'non_nullish',
]);

/**
 * Schema types with a list of nested schemas in an `options` property.
 */
const OPTIONS_TYPES = new Set(['union', 'variant', 'intersect']);

/**
 * Schema types with a list of nested schemas in an `entries` property.
 */
const ENTRIES_TYPES = new Set([
  'object',
  'loose_object',
  'strict_object',
  'object_with_rest',
]);

/**
 * Schema types with a list of nested schemas in an `items` property.
 */
const ITEMS_TYPES = new Set([
  'tuple',
  'loose_tuple',
  'strict_tuple',
  'tuple_with_rest',
]);

/**
 * Returns a shallow clone of `node` with a fresh `~standard` accessor bound
 * to the clone instead of the original schema.
 */
function _clone(node: AnyNode, overrides: AnyNode): AnyNode {
  return {
    ...node,
    ...overrides,
    get '~standard'() {
      return _getStandardProps(this);
    },
  };
}

/**
 * Deeply walks a schema tree built with `Recur` placeholders and replaces
 * every occurrence found in a supported nested position with `self`.
 *
 * @param node The schema (sub)tree to resolve.
 * @param self The schema that `Recur` should resolve to.
 *
 * @returns The resolved schema (sub)tree.
 *
 * @internal
 */
// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function _resolveRecur(node: any, self: unknown): any {
  if (node === Recur) {
    return self;
  }

  if (!node || typeof node !== 'object' || node.kind !== 'schema') {
    return node;
  }

