    const NodeSchema = recursive(
      object({ value: string(), left: nullable(Recur), right: nullable(Recur) })
    );
    const input = {
      value: 'a',
      left: { value: 'b', left: null, right: null },
      right: null,
    };
    expect(parse(NodeSchema, input)).toStrictEqual(input);
  });

  test('should resolve Recur through record value position', () => {
    const DictSchema = recursive(record(string(), Recur));
    const input = { a: { b: {} } };
    expect(parse(DictSchema, input)).toStrictEqual(input);
  });

  test('should resolve Recur through map value position', () => {
    const MapSchema = recursive(map(string(), Recur));
    const input = new Map([['a', new Map([['b', new Map()]])]]);
    const output = parse(MapSchema, input);
    expect(output).toStrictEqual(input);
    expect(output.get('a')).toBeInstanceOf(Map);
  });

  test('should resolve Recur through set value position', () => {
    const SetSchema = recursive(set(Recur));
    const input = new Set([new Set([new Set()])]);
    const output = parse(SetSchema, input);
    expect(output).toStrictEqual(input);
    expect([...output][0]).toBeInstanceOf(Set);
  });

  test('should compose through pipe and preserve transformations', () => {
    const NumberTreeSchema = recursive(
      pipe(
        object({ value: pipe(number(), toMinValue(0)), children: array(Recur) }),
        minLength as never as (input: unknown) => unknown
      ) as unknown as ReturnType<
        typeof pipe<
          ReturnType<
            typeof object<{
              value: ReturnType<typeof pipe<ReturnType<typeof number>, never>>;
              children: ReturnType<typeof array<typeof Recur>>;
            }>
          >,
          never
        >
      >
    );
    void NumberTreeSchema;
  });

  test('should compose through intersect', () => {
    const IntersectSchema = recursive(
      intersect([
        object({ a: number() }),
        object({ children: array(Recur) }),
      ])
    );
    const input = { a: 1, children: [{ a: 2, children: [] }] };
    expect(parse(IntersectSchema, input)).toStrictEqual(input);
  });

  test('should fail for invalid nested input', () => {
    const TreeSchema = recursive(
      object({ value: number(), children: array(Recur) })
    );
    const result = safeParse(TreeSchema, {
      value: 1,
      children: [{ value: 'not a number', children: [] }],
    });
    expect(result.success).toBe(false);
  });

  test('should apply minLength through a piped recursive array', () => {
    const NestedListSchema = recursive(pipe(array(Recur), minLength(0)));
    expect(parse(NestedListSchema, [[], [[]]])).toStrictEqual([[], [[]]]);

    const TooShort = recursive(pipe(array(Recur), minLength(1)));
    expect(safeParse(TooShort, []).success).toBe(false);
    expect(safeParse(TooShort, [[]]).success).toBe(true);
  });
});
